import{_ as s,o as r,c as a,ag as t}from"./chunks/framework.DXGyWiRo.js";const p=JSON.parse('{"title":"Risk levels and dry-run preview","description":"How Aerosol labels scan results with risk levels, merges nested paths for cleanup, and why dry-run preview stays the default workflow.","frontmatter":{"title":"Risk levels and dry-run preview","description":"How Aerosol labels scan results with risk levels, merges nested paths for cleanup, and why dry-run preview stays the default workflow.","date":"2026-04-05T00:00:00.000Z"},"headers":[],"relativePath":"blog/risk-levels-dry-run.md","filePath":"blog/risk-levels-dry-run.md","lastUpdated":1775592403000}'),n={name:"blog/risk-levels-dry-run.md"};function l(o,e,i,d,u,h){return r(),a("div",null,[...e[0]||(e[0]=[t('<h1 id="risk-levels-and-dry-run-preview" tabindex="-1">Risk levels and dry-run preview <a class="header-anchor" href="#risk-levels-and-dry-run-preview" aria-label="Permalink to &quot;Risk levels and dry-run preview&quot;">​</a></h1><p>Aerosol’s scan results are grouped so you can filter <strong>safer</strong> candidates (typical caches, logs you can regenerate) from items that need <strong>review</strong> (anything ambiguous or tied to apps you still use).</p><h2 id="why-risk-instead-of-a-single-list" tabindex="-1">Why “risk” instead of a single list <a class="header-anchor" href="#why-risk-instead-of-a-single-list" aria-label="Permalink to &quot;Why “risk” instead of a single list&quot;">​</a></h2><p>Opaque “junk file” lists train people to click <strong>Clean all</strong>. We’d rather show <strong>what</strong> matched and <strong>why</strong>, so you can align deletes with your comfort level — especially on dev machines where a “cache” might still be warming up the next build.</p><h2 id="dry-run-by-default" tabindex="-1">Dry-run by default <a class="header-anchor" href="#dry-run-by-default" aria-label="Permalink to &quot;Dry-run by default&quot;">​</a></h2><p>The workflow encourages <strong>preview</strong> before delete: you see sizes, paths, and merged selections. Batch operations still apply to explicit choices — nothing is removed until you confirm.</p><h2 id="merged-paths-and-nested-folders" tabindex="-1">Merged paths and nested folders <a class="header-anchor" href="#merged-paths-and-nested-folders" aria-label="Permalink to &quot;Merged paths and nested folders&quot;">​</a></h2><p>When many files sit under one tree, Aerosol can <strong>merge</strong> nested paths so you’re not toggling hundreds of checkboxes for one directory. Expand when you need line-by-line control.</p><h2 id="plugins-and-heuristics" tabindex="-1">Plugins and heuristics <a class="header-anchor" href="#plugins-and-heuristics" aria-label="Permalink to &quot;Plugins and heuristics&quot;">​</a></h2><p>Built-in awareness (Docker, Git, common dev caches) will grow over time. If a rule feels wrong for your setup, <a href="https://github.com/januscaler/aerosol/issues" target="_blank" rel="noreferrer">open an issue</a> — heuristics should stay explainable, not magical.</p><p>Risk labels are hints, not guarantees. Backups and version control still beat any cleaner when something matters.</p>',11)])])}const g=s(n,[["render",l]]);export{p as __pageData,g as default};
